import React, { useState } from 'react';
import toast from 'react-hot-toast';

const MOCK_STUDENTS = [
  { id:1, adm:'ADM2501', name:'Aarav Sharma',  cls:'Class 10', sec:'A', parent:'Rajesh Sharma',  phone:'9876543210', cat:'General', fee:'paid',    status:'active' },
  { id:2, adm:'ADM2502', name:'Priya Singh',   cls:'Class 8',  sec:'B', parent:'Manoj Singh',    phone:'9765432100', cat:'OBC',     fee:'pending',  status:'active' },
  { id:3, adm:'ADM2503', name:'Rohit Gupta',   cls:'Class 12', sec:'A', parent:'Suresh Gupta',   phone:'9988776655', cat:'General', fee:'paid',     status:'active' },
  { id:4, adm:'ADM2504', name:'Ananya Patel',  cls:'Class 6',  sec:'C', parent:'Deepak Patel',   phone:'9765432108', cat:'SC',      fee:'partial',  status:'active' },
  { id:5, adm:'ADM2505', name:'Dev Kumar',     cls:'Class 11', sec:'B', parent:'Anil Kumar',     phone:'9543218760', cat:'General', fee:'pending',  status:'active' },
  { id:6, adm:'ADM2506', name:'Sakshi Verma',  cls:'Class 9',  sec:'A', parent:'Vivek Verma',    phone:'9812345670', cat:'General', fee:'paid',     status:'active' },
  { id:7, adm:'ADM2507', name:'Arjun Mishra',  cls:'Class 7',  sec:'A', parent:'Sunil Mishra',   phone:'9765001234', cat:'OBC',     fee:'paid',     status:'active' },
  { id:8, adm:'ADM2508', name:'Neha Tiwari',   cls:'Class 10', sec:'B', parent:'Ramesh Tiwari',  phone:'9634567890', cat:'General', fee:'partial',  status:'active' },
  { id:9, adm:'ADM2509', name:'Vikram Joshi',  cls:'Class 8',  sec:'A', parent:'Kailash Joshi',  phone:'9876001234', cat:'EWS',     fee:'pending',  status:'active' },
  { id:10,adm:'ADM2510', name:'Kavya Rao',     cls:'Class 6',  sec:'A', parent:'Naresh Rao',     phone:'9754321098', cat:'General', fee:'paid',     status:'active' },
];

const CLASSES = ['Class 1','Class 2','Class 3','Class 4','Class 5','Class 6','Class 7','Class 8','Class 9','Class 10','Class 11','Class 12'];
const FEE_BADGE = { paid:['#D1FAE5','#065F46','Paid'], pending:['#FEE2E2','#991B1B','Pending'], partial:['#FEF3C7','#92400E','Partial'] };

const inp = { width:'100%', padding:'9px 12px', border:'1.5px solid #E5E7EB', borderRadius:8, fontSize:13, outline:'none', fontFamily:'inherit' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };

export default function Students() {
  const [students, setStudents] = useState(MOCK_STUDENTS);
  const [search, setSearch]     = useState('');
  const [filterCls, setFilterCls] = useState('');
  const [filterFee, setFilterFee] = useState('');
  const [showAdd, setShowAdd]   = useState(false);
  const [step, setStep]         = useState(1);
  const [form, setForm]         = useState({
    firstName:'', lastName:'', dob:'', gender:'male', blood:'', category:'general',
    aadhaar:'', religion:'', class_:'', section:'A', admDate: new Date().toISOString().split('T')[0],
    prevSchool:'', fatherName:'', motherName:'', phone:'', altPhone:'', email:'', address:''
  });

  const filtered = students.filter(s => {
    const matchSearch = s.name.toLowerCase().includes(search.toLowerCase()) || s.adm.includes(search) || s.phone.includes(search);
    const matchCls    = !filterCls || s.cls === filterCls;
    const matchFee    = !filterFee || s.fee === filterFee;
    return matchSearch && matchCls && matchFee;
  });

  const handleAdd = (e) => {
    e.preventDefault();
    if (step < 3) { setStep(step + 1); return; }
    const newStudent = {
      id: students.length + 1,
      adm: `ADM25${String(students.length + 11).padStart(2,'0')}`,
      name: `${form.firstName} ${form.lastName}`,
      cls: form.class_, sec: form.section,
      parent: form.fatherName, phone: form.phone,
      cat: form.category, fee: 'pending', status: 'active'
    };
    setStudents([newStudent, ...students]);
    toast.success(`Student ${newStudent.name} admitted! Admission No: ${newStudent.adm}`);
    setShowAdd(false);
    setStep(1);
    setForm({ firstName:'',lastName:'',dob:'',gender:'male',blood:'',category:'general',aadhaar:'',religion:'',class_:'',section:'A',admDate:new Date().toISOString().split('T')[0],prevSchool:'',fatherName:'',motherName:'',phone:'',altPhone:'',email:'',address:'' });
  };

  const s = { padding:'0 16px' };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
        <div><h2 style={{fontSize:20,fontWeight:700}}>Students</h2><p style={{fontSize:12,color:'#6B7280',marginTop:2}}>{filtered.length} of {students.length} students</p></div>
        <div style={{display:'flex',gap:10}}>
          <button style={{padding:'8px 14px',border:'1.5px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:12,fontWeight:600,cursor:'pointer'}}>📥 Export</button>
          <button onClick={()=>setShowAdd(true)} style={{padding:'8px 18px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Admission</button>
        </div>
      </div>

      <div style={{display:'flex',gap:10,marginBottom:14,flexWrap:'wrap'}}>
        <input placeholder="🔍 Search name, admission no, phone…" value={search} onChange={e=>setSearch(e.target.value)}
          style={{...inp,maxWidth:280,flex:1}}/>
        <select value={filterCls} onChange={e=>setFilterCls(e.target.value)} style={{...inp,width:'auto'}}>
          <option value=''>All Classes</option>
          {CLASSES.map(c=><option key={c}>{c}</option>)}
        </select>
        <select value={filterFee} onChange={e=>setFilterFee(e.target.value)} style={{...inp,width:'auto'}}>
          <option value=''>Fee: All</option>
          <option value='paid'>Paid</option>
          <option value='pending'>Pending</option>
          <option value='partial'>Partial</option>
        </select>
      </div>

      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Adm No','Student','Class','Parent / Phone','Category','Fee','Status','Actions'].map(h=>(
              <th key={h} style={{padding:'9px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:600,textTransform:'uppercase',borderBottom:'0.5px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {filtered.length === 0 && <tr><td colSpan={8} style={{padding:40,textAlign:'center',color:'#9CA3AF'}}>No students found</td></tr>}
            {filtered.map(s=>{
              const [bg,c,label] = FEE_BADGE[s.fee] || FEE_BADGE.pending;
              return (
                <tr key={s.id} style={{borderBottom:'0.5px solid #F3F4F6'}}>
                  <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{s.adm}</td>
                  <td style={{padding:'10px 12px'}}>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <div style={{width:28,height:28,borderRadius:7,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#1E1B4B',flexShrink:0}}>{s.name[0]}</div>
                      <span style={{fontWeight:600}}>{s.name}</span>
                    </div>
                  </td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{s.cls} {s.sec}</td>
                  <td style={{padding:'10px 12px'}}><div style={{fontWeight:500}}>{s.parent}</div><div style={{fontSize:10,color:'#9CA3AF'}}>{s.phone}</div></td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#F3F4F6',color:'#374151'}}>{s.cat}</span></td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:bg,color:c}}>{label}</span></td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#D1FAE5',color:'#065F46'}}>Active</span></td>
                  <td style={{padding:'10px 12px'}}>
                    <div style={{display:'flex',gap:5}}>
                      <button onClick={()=>toast(`Viewing ${s.name}`,'info')} style={{padding:'4px 10px',border:'1px solid #E5E7EB',borderRadius:6,background:'#fff',fontSize:11,cursor:'pointer'}}>View</button>
                      <button onClick={()=>toast.success(`ID Card for ${s.name} generated!`)} style={{padding:'4px 10px',border:'1px solid #E5E7EB',borderRadius:6,background:'#fff',fontSize:11,cursor:'pointer'}}>ID</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        <div style={{padding:'10px 14px',borderTop:'0.5px solid #E5E7EB',fontSize:11,color:'#6B7280'}}>
          Showing {filtered.length} students
        </div>
      </div>

      {/* ADD STUDENT MODAL */}
      {showAdd && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.45)',zIndex:300,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:640,maxWidth:'100%',maxHeight:'90vh',overflow:'hidden',display:'flex',flexDirection:'column'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',alignItems:'center',justifyContent:'space-between',flexShrink:0}}>
              <div style={{fontWeight:700,fontSize:15}}>🎓 New Student Admission</div>
              <button onClick={()=>{setShowAdd(false);setStep(1);}} style={{background:'#F3F4F6',border:'none',borderRadius:7,width:30,height:30,cursor:'pointer',fontSize:16}}>✕</button>
            </div>

            {/* Steps */}
            <div style={{display:'flex',padding:'14px 20px',borderBottom:'0.5px solid #F3F4F6',gap:0,flexShrink:0}}>
              {['Student Info','Parent Info','Academic'].map((label,i)=>{
                const n = i+1;
                const done = step > n;
                const active = step === n;
                return (
                  <div key={n} style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',gap:5,position:'relative'}}>
                    {i < 2 && <div style={{position:'absolute',top:12,left:'50%',right:'-50%',height:1,background:done?'#1E1B4B':'#E5E7EB',zIndex:0}}/>}
                    <div style={{width:24,height:24,borderRadius:'50%',background:done||active?'#1E1B4B':'#F3F4F6',color:done||active?'#fff':'#9CA3AF',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,position:'relative',zIndex:1}}>{done?'✓':n}</div>
                    <div style={{fontSize:10,fontWeight:600,color:active?'#1E1B4B':'#9CA3AF'}}>{label}</div>
                  </div>
                );
              })}
            </div>

            <form onSubmit={handleAdd} style={{flex:1,overflowY:'auto',padding:20}}>
              {step===1 && (
                <div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <div><label style={lbl}>First Name <span style={{color:'#DC2626'}}>*</span></label><input required value={form.firstName} onChange={e=>setForm({...form,firstName:e.target.value})} placeholder="First name" style={inp}/></div>
                    <div><label style={lbl}>Last Name</label><input value={form.lastName} onChange={e=>setForm({...form,lastName:e.target.value})} placeholder="Last name" style={inp}/></div>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                    <div><label style={lbl}>Date of Birth <span style={{color:'#DC2626'}}>*</span></label><input required type="date" value={form.dob} onChange={e=>setForm({...form,dob:e.target.value})} style={inp}/></div>
                    <div><label style={lbl}>Gender</label><select value={form.gender} onChange={e=>setForm({...form,gender:e.target.value})} style={inp}><option value="male">Male</option><option value="female">Female</option><option value="other">Other</option></select></div>
                    <div><label style={lbl}>Blood Group</label><select value={form.blood} onChange={e=>setForm({...form,blood:e.target.value})} style={inp}><option value="">Select</option>{['A+','A-','B+','B-','O+','O-','AB+','AB-'].map(b=><option key={b}>{b}</option>)}</select></div>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <div><label style={lbl}>Category</label><select value={form.category} onChange={e=>setForm({...form,category:e.target.value})} style={inp}><option value="general">General</option><option value="obc">OBC</option><option value="sc">SC</option><option value="st">ST</option><option value="ews">EWS</option></select></div>
                    <div><label style={lbl}>Religion</label><input value={form.religion} onChange={e=>setForm({...form,religion:e.target.value})} placeholder="e.g. Hindu, Muslim, Christian" style={inp}/></div>
                  </div>
                  <div><label style={lbl}>Aadhaar Number</label><input value={form.aadhaar} onChange={e=>setForm({...form,aadhaar:e.target.value})} placeholder="12-digit Aadhaar number" style={inp}/></div>
                </div>
              )}

              {step===2 && (
                <div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <div><label style={lbl}>Father's Name <span style={{color:'#DC2626'}}>*</span></label><input required value={form.fatherName} onChange={e=>setForm({...form,fatherName:e.target.value})} placeholder="Father's full name" style={inp}/></div>
                    <div><label style={lbl}>Mother's Name</label><input value={form.motherName} onChange={e=>setForm({...form,motherName:e.target.value})} placeholder="Mother's full name" style={inp}/></div>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                    <div><label style={lbl}>Primary Mobile <span style={{color:'#DC2626'}}>*</span></label><input required value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} placeholder="10-digit mobile" style={inp}/></div>
                    <div><label style={lbl}>Alt. Mobile</label><input value={form.altPhone} onChange={e=>setForm({...form,altPhone:e.target.value})} placeholder="Optional" style={inp}/></div>
                    <div><label style={lbl}>Email</label><input type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})} placeholder="parent@email.com" style={inp}/></div>
                  </div>
                  <div><label style={lbl}>Address <span style={{color:'#DC2626'}}>*</span></label><textarea required value={form.address} onChange={e=>setForm({...form,address:e.target.value})} placeholder="Full residential address" rows={3} style={{...inp,resize:'vertical'}}/></div>
                </div>
              )}

              {step===3 && (
                <div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                    <div>
                      <label style={lbl}>Class <span style={{color:'#DC2626'}}>*</span></label>
                      <select required value={form.class_} onChange={e=>setForm({...form,class_:e.target.value})} style={inp}>
                        <option value="">Select Class</option>
                        {CLASSES.map(c=><option key={c}>{c}</option>)}
                      </select>
                    </div>
                    <div><label style={lbl}>Section</label><select value={form.section} onChange={e=>setForm({...form,section:e.target.value})} style={inp}><option>A</option><option>B</option><option>C</option><option>D</option></select></div>
                    <div><label style={lbl}>Admission Date</label><input type="date" value={form.admDate} onChange={e=>setForm({...form,admDate:e.target.value})} style={inp}/></div>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <div><label style={lbl}>Previous School</label><input value={form.prevSchool} onChange={e=>setForm({...form,prevSchool:e.target.value})} placeholder="Name of previous school" style={inp}/></div>
                    <div><label style={lbl}>Previous Class / Marks %</label><input placeholder="e.g. Class 5 · 82%" style={inp}/></div>
                  </div>
                  <div style={{padding:14,background:'#EDE9F8',borderRadius:10,fontSize:12,color:'#1E1B4B'}}>
                    ℹ️ Admission number will be auto-generated. Fee receipt PDF will be available after saving.
                  </div>
                </div>
              )}

              <div style={{display:'flex',gap:10,justifyContent:'flex-end',marginTop:20,paddingTop:16,borderTop:'0.5px solid #E5E7EB'}}>
                {step > 1 && <button type="button" onClick={()=>setStep(step-1)} style={{padding:'9px 18px',border:'1.5px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:13,cursor:'pointer'}}>← Back</button>}
                <button type="button" onClick={()=>{setShowAdd(false);setStep(1);}} style={{padding:'9px 18px',border:'1.5px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" style={{padding:'9px 22px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:700,cursor:'pointer'}}>
                  {step < 3 ? 'Next →' : '💾 Save & Admit'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
